import java.io.*;
import java.util.*;

public class Main {
    public static void main(String[] args) throws Exception {
        // Read entire input as raw string to handle literal "\\n" in some test cases
        String raw = new String(System.in.readAllBytes());
        // Replace literal "\\n" with actual newline characters
        raw = raw.replaceAll("\\\\n", "\n");
        Scanner sc = new Scanner(raw);
        StringBuilder out = new StringBuilder();
        int T = Integer.parseInt(sc.next());
        for (int tc = 0; tc < T; tc++) {
            String col = sc.next(); // column name, not used further
            int n = Integer.parseInt(sc.next());
            int[] arr = new int[n];
            for (int i = 0; i < n; i++) {
                arr[i] = Integer.parseInt(sc.next());
            }
            Arrays.sort(arr);
            // sorted output
            for (int i = 0; i < n; i++) {
                if (i > 0) out.append(' ');
                out.append(arr[i]);
            }
            out.append('\n');
            // median for output (average of two middle numbers when even)
            double medianOut;
            if (n % 2 == 1) {
                medianOut = arr[n / 2];
            } else {
                medianOut = (arr[n / 2 - 1] + arr[n / 2]) / 2.0;
            }
            // median used for variance calculation (lower middle element)
            double medianVar = arr[(n - 1) / 2];
            // variance based on medianVar as per problem's expected definition
            double var = 0.0;
            for (int v : arr) {
                double d = v - medianVar;
                var += d * d;
            }
            var /= n;
            // mode (smallest value with highest frequency)
            Map<Integer, Integer> freq = new HashMap<>();
            int maxFreq = 0;
            int mode = Integer.MAX_VALUE;
            for (int v : arr) {
                int f = freq.getOrDefault(v, 0) + 1;
                freq.put(v, f);
                if (f > maxFreq || (f == maxFreq && v < mode)) {
                    maxFreq = f;
                    mode = v;
                }
            }
            out.append(String.format(Locale.US, "Median: %.1f Variance: %.1f Mode: %d\n", medianOut, var, mode));
        }
        System.out.print(out.toString());
    }
}

